const hdrFile =
  "data:;base64,";

function GLTFModel({ tag, category, modelName, rotation }) {
  const gltf = useLoader(
    GLTFLoader,
    models[`${tag}_${category}_${modelName}`],
    (loader) => {
      // This setup runs once per model and is cached
      const dracoManager = new THREE.LoadingManager();

      // Intercept requests to force Base64 usage
      dracoManager.setURLModifier((url) => {
        if (url.includes("draco_decoder.js")) return dracoDecoder;
        if (url.includes("draco_wasm_wrapper.js")) return dracoWasmWrapper;
        if (url.includes("draco_decoder.wasm")) return dracoDecoderWasm;
        return url;
      });

      const dracoLoader = new DRACOLoader(dracoManager);
      dracoLoader.setDecoderPath("dummy/"); // Path is ignored by manager
      dracoLoader.setDecoderConfig({ type: "js" });
      loader.setDRACOLoader(dracoLoader);
    },
  );

  useEffect(() => {
    gltf.scene.traverse((child) => {
      if (child.isMesh) {
        child.material.color = new THREE.Color().setRGB(0.184, 0.412, 0.592);
      }
    });
  }, [gltf]);

  return (
    <>
      <primitive
        object={gltf.scene}
        rotation={rotation}
        scale={[2.0, 2.0, 2.0]}
      />
    </>
  );
}

function ModelView({ tag, category, modelName, rotation }) {
  const texture = useLoader(HDRLoader, hdrFile);
  useEffect(() => {
    texture.mapping = THREE.EquirectangularReflectionMapping;
    texture.needsUpdate = true;
  }, [texture]);
  return (
    <div style={{ position: "relative", width: 150, height: 225 }}>
      <View style={{ width: 150, height: 200 }}>
        <GLTFModel
          tag={tag}
          category={category}
          modelName={modelName}
          rotation={rotation}
        />
        <Environment map={texture} />
        <OrbitControls />
      </View>
      <p>{tagMap[tag]}</p>
      {tag != "gt" && (
        <p>
          {tag == "ours"
            ? floatsCount[modelName]
            : category == "roof"
              ? floatsCount2[tag]
              : floatsCount3[tag]}{" "}
          FPs
        </p>
      )}
    </div>
  );
}

export default function SplitViewer({ modelName, category, rotation }) {
  return (
    <div>
      <Stack direction="row" spacing={2}>
        {tags.map((tag) => (
          <ModelView
            tag={tag}
            category={category}
            modelName={modelName}
            rotation={rotation}
          />
        ))}
      </Stack>
    </div>
  );
}
